from agents import Runner
from agents.exceptions import OutputGuardrailTripwireTriggered
import asyncio

async def run_with_vex_guardrails(user_message: str, trace_id: str) -> str:
    context = {"trace_id": trace_id}

    try:
        result = await Runner.run(
            triage_agent,
            input=user_message,
            context=context,
            max_turns=10  # prevent handoff loops
        )
        return result.final_output.response

    except OutputGuardrailTripwireTriggered as e:
        # Vex blocked the output — log and return safe fallback
        await vex.log_event_async(
            event_type="guardrail_block",
            trace_id=trace_id,
            details={
                "agent": e.guardrail.guardrail_function.__name__,
                "reason": str(e)
            }
        )
        return "I'm unable to provide that response. Please contact support."

    except Exception as e:
        await vex.log_event_async(
            event_type="unexpected_error",
            trace_id=trace_id,
            details={"error": str(e)}
        )
        raise

# Example usage
if __name__ == "__main__":
    response = asyncio.run(
        run_with_vex_guardrails(
            user_message="What is my current invoice amount?",
            trace_id="trace-abc-123"
        )
    )
    print(response)
